using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private readonly PriceCalculator _calculator = new();

    // --- CalculateTotal: DataRow for inline primitive combinations ---

    [TestMethod]
    [DataRow(10.00, 1, 0.0, 10.00, DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0, 50.00, DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00, DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62, DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00, 10, 0.20, 0.00, DisplayName = "Zero price")]
    [DataRow(99.99, 0, 0.15, 0.00, DisplayName = "Zero quantity")]
    public void CalculateTotal_WithValidInputs_ReturnsExpected(
        double unitPrice, int quantity, double taxRate, double expected)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expected, result);
    }

    [TestMethod]
    [DataRow(-1.00, 1, 0.10, "unitPrice", DisplayName = "Negative price throws")]
    [DataRow(10.00, -1, 0.10, "quantity", DisplayName = "Negative quantity throws")]
    [DataRow(10.00, 1, -0.01, "taxRate", DisplayName = "Negative tax rate throws")]
    [DataRow(10.00, 1, 1.01, "taxRate", DisplayName = "Tax rate > 1 throws")]
    public void CalculateTotal_WithInvalidInputs_ThrowsArgumentOutOfRange(
        double unitPrice, int quantity, double taxRate, string expectedParam)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));

        Assert.AreEqual(expectedParam, ex.ParamName);
    }

    // --- ApplyDiscount: DynamicData with ValueTuples for type-safe complex data ---

    [TestMethod]
    [DynamicData(nameof(DiscountTestData))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpected(
        decimal price, decimal discountPercent, decimal expected)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<(decimal price, decimal discountPercent, decimal expected)> DiscountTestData =>
    [
        (100m, 10m, 90m),
        (200m, 25m, 150m),
        (50m, 0m, 50m),
        (80m, 100m, 0m),
        (99.99m, 50m, 49.995m),
    ];

    [TestMethod]
    [DataRow(-1.0, DisplayName = "Discount below 0 throws")]
    [DataRow(100.1, DisplayName = "Discount above 100 throws")]
    public void ApplyDiscount_WithInvalidPercent_ThrowsArgumentOutOfRange(double discountPercent)
    {
        var ex = Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(100m, (decimal)discountPercent));

        Assert.AreEqual("discountPercent", ex.ParamName);
    }

    // --- FormatPrice: DynamicData with TestDataRow for display names ---

    [TestMethod]
    [DynamicData(nameof(FormatPriceTestData))]
    public void FormatPrice_ReturnsFormattedString(
        decimal price, string currencySymbol, string expected)
    {
        var result = _calculator.FormatPrice(price, currencySymbol);

        Assert.AreEqual(expected, result);
    }

    public static IEnumerable<TestDataRow<(decimal price, string symbol, string expected)>> FormatPriceTestData =>
    [
        new((9.99m, "$", "$9.99")) { DisplayName = "USD format" },
        new((1234.5m, "€", "€1234.50")) { DisplayName = "Euro with padding" },
        new((0m, "£", "£0.00")) { DisplayName = "Zero in GBP" },
    ];
}

